interface.signature:
ConfigModule.forRoot({
  isGlobal: true,
  envFilePath: ['.env.development', '.env'],
  validationSchema: envSchema,
  validationOptions: {
    abortEarly: false,
    allowUnknown: true
  }
})

import * as Joi from 'joi';

export const envSchema = Joi.object({
  NODE_ENV: Joi.string().valid('development', 'staging', 'production').required(),
  PORT: Joi.number().default(3000),
  API_PREFIX: Joi.string().default('api'),
  DATABASE_URL: Joi.string().required(),
  JWT_SECRET: Joi.string().min(32).required(),
  JWT_ACCESS_EXPIRATION: Joi.string().default('15m'),
  JWT_REFRESH_EXPIRATION: Joi.string().default('7d'),
}).unknown();

// Required Variables (must be in .env or validation fails) NODE_ENV: 'development' | 'staging' | 'production' DATABASE_URL: string (PostgreSQL or MongoDB connection string) JWT_SECRET: string (minimum 32 characters)
// Optional Variables (have defaults) PORT: number (default: 3000) API_PREFIX: string (default: 'api') JWT_ACCESS_EXPIRATION: string (default: '15m') JWT_REFRESH_EXPIRATION: string (default: '7d')
// Future Epic Variables (optional, commented out in .env.example) AWS_REGION, AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY, S3_BUCKET (Epic 4) TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, TWILIO_PHONE_NUMBER (Epic 5) SENDGRID_API_KEY, FROM_EMAIL (Epic 5) SENTRY_DSN (Epic 7)
